examples.code:
const edades = [14, 22, 17, 31, 16, 25];

const mayoresDeEdad = edades.filter(edad => edad >= 18);
console.log(mayoresDeEdad); // [22, 31, 25]

const inventario = [
  { producto: 'Camisa', stock: 0 },
  { producto: 'Pantalón', stock: 5 },
  { producto: 'Zapatos', stock: 0 },
  { producto: 'Gorra', stock: 12 }
];

const disponibles = inventario.filter(item => item.stock > 0);
console.log(disponibles.length); // 2
console.log(disponibles[0].producto); // 'Pantalón'

const palabras = ['sol', 'mariposa', 'luz', 'programación', 'mar'];

const largas = palabras.filter(p => p.length > 4);
console.log(largas); // ['mariposa', 'programación']

// Encadenar filter + map
const largasEnMayus = palabras
  .filter(p => p.length > 4)
  .map(p => p.toUpperCase());
console.log(largasEnMayus); // ['MARIPOSA', 'PROGRAMACIÓN']

